#!/usr/bin/env node
// gen-contract-fixtures-v3.mjs — Emit a data-only Rust module from the real v3
// (multi-asset solvency) Groth16 fixtures so the contract v3 test verifies
// ACTUAL proofs through the on-chain pairing check (no mock VK).
//
// Reads:
//   fixtures/v3/verification_key_v3.json
//   fixtures/v3/{solvent,priced_insolvent,one_asset_underwater}/{proof,public}.json
// Writes:
//   contracts/stellaris/src/test_fixtures_v3.rs   (@generated, data only)
//
// v3 statement has 8 public signals:
//   [ aggregateSolvent, reserveCommitment, priceCommitment,
//     assetSolvent[0..3], period ]
// so VK.ic length is 9. Reuses G1c/G2c from test_fixtures.rs; preserves the
// snarkjs [c0,c1] Fp2 ordering as (x1=c0, x2=c1) exactly like the v1/v2 gens.
//
// Usage: node setup/gen-contract-fixtures-v3.mjs

import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const FIX = join(ROOT, "fixtures", "v3");
const OUT = join(ROOT, "contracts/stellaris/src/test_fixtures_v3.rs");

const rd = (p) => JSON.parse(readFileSync(p, "utf8"));

function g1(arr) {
  return { x: String(arr[0]), y: String(arr[1]) };
}
function g2(arr) {
  return {
    x1: String(arr[0][0]),
    x2: String(arr[0][1]),
    y1: String(arr[1][0]),
    y2: String(arr[1][1]),
  };
}

const vk = rd(join(FIX, "verification_key_v3.json"));
const vkData = {
  alpha: g1(vk.vk_alpha_1),
  beta: g2(vk.vk_beta_2),
  gamma: g2(vk.vk_gamma_2),
  delta: g2(vk.vk_delta_2),
  ic: vk.IC.map(g1),
};

function scenario(name) {
  const proof = rd(join(FIX, name, "proof.json"));
  const signals = rd(join(FIX, name, "public.json")).map(String);
  return {
    a: g1(proof.pi_a),
    b: g2(proof.pi_b),
    c: g1(proof.pi_c),
    signals,
  };
}

const solvent = scenario("solvent");
const pricedInsolvent = scenario("priced_insolvent");
const oneAssetUnderwater = scenario("one_asset_underwater");

const g1Lit = (g) => `G1c { x: "${g.x}", y: "${g.y}" }`;
const g2Lit = (g) =>
  `G2c { x1: "${g.x1}", x2: "${g.x2}", y1: "${g.y1}", y2: "${g.y2}" }`;
const sigLit = (s) => `[${s.map((v) => `"${v}"`).join(", ")}]`;
const icLit = (ic) => ic.map((g) => `    ${g1Lit(g)},`).join("\n");

function proofConst(name, ident, p) {
  return `/// Real v3 Groth16 proof + 8 public signals for the ${name} scenario.
pub const ${ident}: ProofDataV3 = ProofDataV3 {
    a: ${g1Lit(p.a)},
    b: ${g2Lit(p.b)},
    c: ${g1Lit(p.c)},
    signals: ${sigLit(p.signals)},
};`;
}

const body = `//! @generated by setup/gen-contract-fixtures-v3.mjs — DO NOT EDIT BY HAND.
//!
//! Real v3 Groth16 (BLS12-381) verification key, proofs, and 8 public signals
//! for the multi-asset solvency statement (por_v3.circom), produced by
//! setup/ceremony-v3.sh + setup/export-fixtures-v3.sh. Genuine cryptographic
//! artifacts — the contract v3 test verifies them through the real on-chain
//! pairing check.
//!
//! Public-signal order (8): [ aggregateSolvent, reserveCommitment,
//! priceCommitment, assetSolvent[0..3], period ]
//!
//! Regenerate after re-running the v3 ceremony:
//!   node setup/gen-contract-fixtures-v3.mjs

#![cfg(test)]

use crate::test_fixtures::{G1c, G2c};

/// A v3 scenario's proof (A,C in G1; B in G2) and its 8 public signals.
pub struct ProofDataV3 {
    pub a: G1c,
    pub b: G2c,
    pub c: G1c,
    pub signals: [&'static str; 8],
}

/// v3 verification key (IC length = 9 = 8 signals + 1).
pub struct VkDataV3 {
    pub alpha: G1c,
    pub beta: G2c,
    pub gamma: G2c,
    pub delta: G2c,
    pub ic: &'static [G1c],
}

/// Real v3 verification key from the multi-asset trusted setup.
pub const VK_V3: VkDataV3 = VkDataV3 {
    alpha: ${g1Lit(vkData.alpha)},
    beta: ${g2Lit(vkData.beta)},
    gamma: ${g2Lit(vkData.gamma)},
    delta: ${g2Lit(vkData.delta)},
    ic: &[
${icLit(vkData.ic)}
    ],
};

${proofConst("solvent", "SOLVENT_V3", solvent)}

${proofConst("priced-insolvent", "PRICED_INSOLVENT_V3", pricedInsolvent)}

${proofConst("one-asset-underwater", "ONE_ASSET_UNDERWATER_V3", oneAssetUnderwater)}
`;

writeFileSync(OUT, body);
console.log(`[OK] wrote ${OUT}`);
console.log(`     VK_V3.ic length: ${vkData.ic.length} (expect 9)`);
console.log(`     solvent signals:              ${sigLit(solvent.signals)}`);
console.log(`     priced_insolvent signals:     ${sigLit(pricedInsolvent.signals)}`);
console.log(`     one_asset_underwater signals: ${sigLit(oneAssetUnderwater.signals)}`);
